import React from 'react';
import { Text } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface HeadingProps extends SDUIComponentProps {
  text: string;
  color?: string;
  mt?: string;
  mb?: string;
  align?: string;
  testID?: string;
}

export default function HeadingAdapter({
  props,
}: {
  props: HeadingProps;
  context: SDUIContext;
}) {
  const { text, color = 'INTENSE_COLOR_05', mt, mb, align, testID } = props;

  return (
    <Text
      type="headingMDL"
      color={color}
      mt={mt}
      mb={mb}
      align={align}
      testID={testID}
    >
      {text}
    </Text>
  );
}

