import React from 'react';
import { render } from '@testing-library/react-native';
import { adapters, registerAllAdapters } from './index';
import { getDefaultRegistry, getRenderer } from '../registry';
import type { SDUIContext } from '../models';

jest.mock('@semparar/design-system-app', () => {
  const mockReact = require('react');
  const RN = require('react-native');
  return {
    Text: (p: any) => mockReact.createElement(RN.Text, p, p.children),
    Button: (p: any) =>
      mockReact.createElement(
        RN.Text,
        { accessibilityState: { disabled: !!p.disabled }, testID: 'ds-button' },
        p.text,
      ),
    Box: (p: any) => mockReact.createElement(RN.View, p, p.children),
    InputBox: (p: any) =>
      mockReact.createElement(RN.TextInput, { placeholder: p.placeholder }),
    Alert: (p: any) => mockReact.createElement(RN.Text, null, p.label),
    Icon: (p: any) => mockReact.createElement(RN.Text, null, p.name),
    ListTextIcon: (p: any) =>
      mockReact.createElement(
        RN.View,
        null,
        ...(p.items || []).map((item: any, i: number) =>
          mockReact.createElement(RN.Text, { key: i }, item.description),
        ),
      ),
    SeparatorHorizontal: () =>
      mockReact.createElement(RN.View, { testID: 'separator' }),
    CardVehicleTags: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-vehicle-tags' },
        mockReact.createElement(RN.Text, null, p.vehicleName),
        mockReact.createElement(RN.Text, null, p.status),
      ),
    CardPoints: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-points' },
        mockReact.createElement(RN.Text, null, p.title),
        mockReact.createElement(RN.Text, null, p.valuePoints),
      ),
    SearchUsed: (p: any) =>
      mockReact.createElement(RN.TextInput, { placeholder: p.placeholder }),
    DetailTransactionValue: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'detail-transaction-value' },
        mockReact.createElement(RN.Text, null, p.title),
        mockReact.createElement(RN.Text, null, p.points),
      ),
    TagLabel: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'tag-label' },
        mockReact.createElement(RN.Text, null, p.text),
      ),
    CardActivity: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-activity' },
        mockReact.createElement(RN.Text, null, p.title),
        p.description
          ? mockReact.createElement(RN.Text, null, p.description)
          : null,
      ),
    Header: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'ds-header' },
        mockReact.createElement(RN.Text, null, p.title),
        p.iconLeft
          ? mockReact.createElement(RN.Text, null, p.iconLeft)
          : null,
      ),
  };
});

const emptyContext: SDUIContext = {};

describe('SDUI Adapters', () => {
  it('exports all 23 adapters', () => {
    const expected = [
      'heading',
      'text',
      'balance_display',
      'points_input',
      'button',
      'link',
      'alert',
      'list_text_icon',
      'separator',
      'icon_text_row',
      'section_heading',
      'rich_text',
      'voucher_card',
      'empty_state',
      'points_card',
      'tab_bar',
      'transaction_item',
      'date_separator',
      'detail_header',
      'tag_label',
      'key_value_row',
      'card_activity',
      'nav_header',
    ];
    expect(Object.keys(adapters)).toEqual(expected);
  });

  it('registers all adapters to the default registry', () => {
    registerAllAdapters();
    const registry = getDefaultRegistry();

    Object.keys(adapters).forEach(type => {
      expect(getRenderer(registry, type)).toBeDefined();
    });
  });

  describe('HeadingAdapter', () => {
    it('renders heading text', () => {
      const Comp = adapters.heading;
      const { getByText } = render(
        <Comp props={{ text: 'My Title' }} context={emptyContext} />,
      );
      expect(getByText('My Title')).toBeTruthy();
    });
  });

  describe('TextAdapter', () => {
    it('renders text content', () => {
      const Comp = adapters.text;
      const { getByText } = render(
        <Comp props={{ text: 'Hello world' }} context={emptyContext} />,
      );
      expect(getByText('Hello world')).toBeTruthy();
    });
  });

  describe('BalanceDisplayAdapter', () => {
    it('renders label, points, and price', () => {
      const Comp = adapters.balance_display;
      const { getByText } = render(
        <Comp
          props={{
            label: 'Pontos disponíveis:',
            pointsFormatted: '1.500',
            priceFormatted: 'R$ 15,00',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Pontos disponíveis:')).toBeTruthy();
      expect(getByText('1.500')).toBeTruthy();
      expect(getByText('(R$ 15,00)')).toBeTruthy();
    });
  });

  describe('PointsInputAdapter', () => {
    it('renders input with placeholder', () => {
      const Comp = adapters.points_input;
      const { getByPlaceholderText } = render(
        <Comp
          props={{ label: 'Valor em pontos', placeholder: '0' }}
          context={emptyContext}
        />,
      );
      expect(getByPlaceholderText('0')).toBeTruthy();
    });
  });

  describe('ButtonAdapter', () => {
    it('renders button text', () => {
      const Comp = adapters.button;
      const { getByText } = render(
        <Comp props={{ text: 'Continuar' }} context={emptyContext} />,
      );
      expect(getByText('Continuar')).toBeTruthy();
    });

    it('disables button when enabled rule evaluates to false', () => {
      const Comp = adapters.button;
      const context: SDUIContext = { form: { points: 0 } };
      const { getByTestId } = render(
        <Comp
          props={{
            text: 'Submit',
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      const button = getByTestId('ds-button');
      expect(button.props.accessibilityState.disabled).toBe(true);
    });

    it('enables button when enabled rule evaluates to true', () => {
      const Comp = adapters.button;
      const context: SDUIContext = { form: { points: 500 } };
      const { getByTestId } = render(
        <Comp
          props={{
            text: 'Submit',
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      const button = getByTestId('ds-button');
      expect(button.props.accessibilityState.disabled).toBe(false);
    });

    it('respects disabled prop even when enabled rule is true', () => {
      const Comp = adapters.button;
      const context: SDUIContext = { form: { points: 500 } };
      const { getByTestId } = render(
        <Comp
          props={{
            text: 'Submit',
            disabled: true,
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      const button = getByTestId('ds-button');
      expect(button.props.accessibilityState.disabled).toBe(true);
    });
  });

  describe('LinkAdapter', () => {
    it('renders link text', () => {
      const Comp = adapters.link;
      const { getByText } = render(
        <Comp props={{ text: 'Exibir regras' }} context={emptyContext} />,
      );
      expect(getByText('Exibir regras')).toBeTruthy();
    });
  });

  describe('AlertAdapter', () => {
    it('renders alert label', () => {
      const Comp = adapters.alert;
      const { getByText } = render(
        <Comp
          props={{ label: 'Info message', type: 'highlight' }}
          context={emptyContext}
        />,
      );
      expect(getByText('Info message')).toBeTruthy();
    });
  });

  describe('ListTextIconAdapter', () => {
    it('renders list items', () => {
      const Comp = adapters.list_text_icon;
      const items = [
        { icon: 'icon-check', description: 'Item 1' },
        { icon: 'icon-calendar', description: 'Item 2' },
      ];
      const { getByText } = render(
        <Comp props={{ items }} context={emptyContext} />,
      );
      expect(getByText('Item 1')).toBeTruthy();
      expect(getByText('Item 2')).toBeTruthy();
    });
  });

  describe('SeparatorAdapter', () => {
    it('renders separator', () => {
      const Comp = adapters.separator;
      const { getByTestId } = render(
        <Comp props={{}} context={emptyContext} />,
      );
      expect(getByTestId('separator')).toBeTruthy();
    });
  });

  describe('IconTextRowAdapter', () => {
    it('renders icon and text', () => {
      const Comp = adapters.icon_text_row;
      const { getByText } = render(
        <Comp
          props={{ icon: 'icon-check', text: 'Rule description' }}
          context={emptyContext}
        />,
      );
      expect(getByText('icon-check')).toBeTruthy();
      expect(getByText('Rule description')).toBeTruthy();
    });
  });

  describe('SectionHeadingAdapter', () => {
    it('renders section heading', () => {
      const Comp = adapters.section_heading;
      const { getByText } = render(
        <Comp props={{ text: 'Regras de uso' }} context={emptyContext} />,
      );
      expect(getByText('Regras de uso')).toBeTruthy();
    });
  });

  describe('RichTextAdapter', () => {
    it('renders text nodes', () => {
      const Comp = adapters.rich_text;
      const { getByText } = render(
        <Comp
          props={{
            children: [
              { type: 'text', value: 'Hello ' },
              { type: 'text', value: 'world', bold: true },
            ],
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Hello ')).toBeTruthy();
      expect(getByText('world')).toBeTruthy();
    });

    it('renders link nodes', () => {
      const Comp = adapters.rich_text;
      const { getByText } = render(
        <Comp
          props={{
            children: [
              { type: 'text', value: 'Click ' },
              { type: 'link', text: 'here', to: 'app://help' },
            ],
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Click ')).toBeTruthy();
      expect(getByText('here')).toBeTruthy();
    });

    it('renders icon nodes', () => {
      const Comp = adapters.rich_text;
      const { getByText } = render(
        <Comp
          props={{
            children: [
              { type: 'icon', name: 'icon-check' },
            ],
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('icon-check')).toBeTruthy();
    });

    it('renders linebreak between text nodes', () => {
      const Comp = adapters.rich_text;
      const { getByText } = render(
        <Comp
          props={{
            children: [
              { type: 'text', value: 'Line 1' },
              { type: 'br' },
              { type: 'text', value: 'Line 2' },
            ],
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Line 1')).toBeTruthy();
      expect(getByText('Line 2')).toBeTruthy();
    });

    it('returns null for empty children', () => {
      const Comp = adapters.rich_text;
      const { toJSON } = render(
        <Comp props={{ children: [] }} context={emptyContext} />,
      );
      expect(toJSON()).toBeNull();
    });

    it('returns null for missing children', () => {
      const Comp = adapters.rich_text;
      const { toJSON } = render(
        <Comp props={{}} context={emptyContext} />,
      );
      expect(toJSON()).toBeNull();
    });
  });

  describe('VoucherCardAdapter', () => {
    it('renders voucher card with vehicle name and status', () => {
      const Comp = adapters.voucher_card;
      const { getByText } = render(
        <Comp
          props={{
            icon: 'icon-gas-station',
            vehicleName: 'Voucher para abastecimento',
            title: 'Valor em pontos',
            titleDescription: '2500',
            date: 'Data do resgate',
            dateNumber: '20/02/2026',
            statusTitle: 'Status do pedido',
            status: 'Finalizado',
            typeTag: 'success',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Voucher para abastecimento')).toBeTruthy();
      expect(getByText('Finalizado')).toBeTruthy();
    });
  });

  describe('EmptyStateAdapter', () => {
    it('renders empty state with icon and title', () => {
      const Comp = adapters.empty_state;
      const { getByText } = render(
        <Comp
          props={{
            icon: 'icon-shopping-cart',
            title: 'Nenhum pedido feito',
            description: 'Quando você usar seus pontos, eles aparecerão aqui.',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('icon-shopping-cart')).toBeTruthy();
      expect(getByText('Nenhum pedido feito')).toBeTruthy();
      expect(
        getByText('Quando você usar seus pontos, eles aparecerão aqui.'),
      ).toBeTruthy();
    });

    it('renders without description', () => {
      const Comp = adapters.empty_state;
      const { getByText, queryByText } = render(
        <Comp
          props={{
            icon: 'icon-search',
            title: 'Sem resultados',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Sem resultados')).toBeTruthy();
      expect(queryByText('undefined')).toBeNull();
    });
  });

  describe('PointsCardAdapter', () => {
    it('renders points card with title and value', () => {
      const Comp = adapters.points_card;
      const { getByText } = render(
        <Comp
          props={{
            icon: 'icon-benefits',
            title: 'Pontos disponíveis',
            valuePoints: '15.320',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Pontos disponíveis')).toBeTruthy();
      expect(getByText('15.320')).toBeTruthy();
    });
  });

  describe('TabBarAdapter', () => {
    it('renders tab labels', () => {
      const Comp = adapters.tab_bar;
      const { getByText } = render(
        <Comp
          props={{
            tabs: [
              { id: 0, title: 'Todos' },
              { id: 1, title: 'A expirar' },
            ],
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Todos')).toBeTruthy();
      expect(getByText('A expirar')).toBeTruthy();
    });
  });

  describe('TransactionItemAdapter', () => {
    it('renders transaction with icon, title and value', () => {
      const Comp = adapters.transaction_item;
      const { getByText } = render(
        <Comp
          props={{
            icon: 'icon-tag',
            title: 'Pedágio Rodovia Anhanguera',
            value: '+ 150 pontos',
            valueColor: 'green',
            typeLabel: 'Ganhos',
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('icon-tag')).toBeTruthy();
      expect(getByText('Pedágio Rodovia Anhanguera')).toBeTruthy();
      expect(getByText('+ 150 pontos')).toBeTruthy();
      expect(getByText('Ganhos')).toBeTruthy();
    });

    it('hides icon when showIcon is false', () => {
      const Comp = adapters.transaction_item;
      const { queryByText, getByText } = render(
        <Comp
          props={{
            icon: 'icon-less',
            title: 'Pontos expirados',
            value: '- 320 pontos',
            valueColor: 'gray',
            showIcon: false,
          }}
          context={emptyContext}
        />,
      );
      expect(getByText('Pontos expirados')).toBeTruthy();
      expect(queryByText('icon-less')).toBeNull();
    });
  });

  describe('DateSeparatorAdapter', () => {
    it('renders date label', () => {
      const Comp = adapters.date_separator;
      const { getByText } = render(
        <Comp
          props={{ label: '20 de fevereiro' }}
          context={emptyContext}
        />,
      );
      expect(getByText('20 de fevereiro')).toBeTruthy();
    });
  });
});

